import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";

const API_BASE = "http://localhost:5000";

const ProductDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();

  const [product, setProduct] = useState(null);
  const [related, setRelated] = useState([]);
  const [reviews, setReviews] = useState([]);

  const [loading, setLoading] = useState(true);
  const [qty, setQty] = useState(1);

  const [selectedImage, setSelectedImage] = useState("");
  const [activeTab, setActiveTab] = useState("description");

  // Review form
  const [rating, setRating] = useState(5);
  const [comment, setComment] = useState("");
  const [loadingReview, setLoadingReview] = useState(false);

  useEffect(() => {
    fetchProduct();
  }, [id]);

  const fetchProduct = async () => {
    setLoading(true);
    try {
      // Chi tiết sản phẩm
      const res = await fetch(`${API_BASE}/api/products/${id}`);
      const data = await res.json();

      if (data.success) {
        setProduct(data.product);

        if (data.product.images?.length > 0) {
          setSelectedImage(data.product.images[0]);
        }
      }

      // Review
      const rv = await fetch(`${API_BASE}/api/reviews/${id}`);
      const rvData = await rv.json();
      if (rvData.success) setReviews(rvData.reviews);

      // Sản phẩm liên quan
      const rel = await fetch(`${API_BASE}/api/products/${id}/related`);
      const relData = await rel.json();
      if (relData.success) setRelated(relData.products);

    } catch (err) {
      console.log(err);
    }

    setLoading(false);
  };

  // === Thêm vào giỏ ===
  const addToCart = () => {
    const item = {
      _id: product._id,
      name: product.name,
      price: product.discountPrice || product.price,
      image: product.images?.[0] || "",
      qty,
    };

    let cart = JSON.parse(localStorage.getItem("cart") || "[]");

    const exist = cart.find((p) => p._id === item._id);
    if (exist) {
      exist.qty += qty;
    } else {
      cart.push(item);
    }

    localStorage.setItem("cart", JSON.stringify(cart));
    alert("Đã thêm vào giỏ hàng 💗");
  };

  // === Mua ngay ===
  const buyNow = () => {
    addToCart();
    navigate("/cart");
  };

  // === Gửi review ===
  const submitReview = async (e) => {
    e.preventDefault();
    setLoadingReview(true);

    const token = localStorage.getItem("token"); // nếu dùng login

    const res = await fetch(`${API_BASE}/api/reviews`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: token ? `Bearer ${token}` : "",
      },
      body: JSON.stringify({
        productId: id,
        rating,
        comment,
      }),
    });

    const data = await res.json();

    if (!data.success) {
      alert(data.message);
    } else {
      setComment("");
      setRating(5);
      fetchProduct(); // reload review
      alert("Đã gửi đánh giá 💗");
    }

    setLoadingReview(false);
  };

  if (loading)
    return (
      <div className="p-10 text-center text-pink-500 text-xl">
        Đang tải sản phẩm...
      </div>
    );

  if (!product)
    return (
      <div className="p-10 text-center text-red-500 text-xl">
        Không tìm thấy sản phẩm!
      </div>
    );

  const finalPrice = product.discountPrice || product.price;

  return (
    <div className="bg-[#faeef2] min-h-screen py-10">
      <div className="max-w-6xl mx-auto px-4">

        {/* === Image + info === */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-10 bg-white rounded-3xl p-8 shadow-lg">

          {/* Ảnh chính */}
          <div>
            <div className="rounded-3xl overflow-hidden border border-pink-200 bg-pink-50">
              <img
                src={API_BASE + selectedImage}
                alt=""
                className="w-full h-[420px] object-contain"
              />
            </div>

            {/* Thumbnails */}
            <div className="flex gap-3 mt-4">
              {product.images?.map((img, i) => (
                <img
                  key={i}
                  src={API_BASE + img}
                  className={`w-20 h-20 object-cover border rounded-xl cursor-pointer ${
                    selectedImage === img ? "border-pink-500" : "border-pink-200"
                  }`}
                  onClick={() => setSelectedImage(img)}
                  alt=""
                />
              ))}
            </div>
          </div>

          {/* Thông tin */}
          <div>
            <h1 className="text-3xl font-bold text-[#4b2c35]">{product.name}</h1>

            {/* Giá */}
            <div className="flex items-end gap-3 mt-3">
              <span className="text-3xl font-bold text-pink-600">
                {finalPrice.toLocaleString()}₫
              </span>

              {product.discountPrice && (
                <span className="line-through text-gray-400">
                  {product.price.toLocaleString()}₫
                </span>
              )}
            </div>

            {/* Stock + Sold */}
            <p className="mt-2 text-gray-600">
              Đã bán: <b className="text-pink-600">{product.sold}</b> — Còn:{" "}
              <b className="text-pink-600">{product.stock}</b>
            </p>

            {/* Số lượng */}
            <div className="mt-5">
              <h4 className="font-medium text-gray-700 mb-1">Số lượng</h4>
              <div className="flex items-center gap-3">
                <button
                  onClick={() => setQty(qty > 1 ? qty - 1 : 1)}
                  className="w-8 h-8 flex items-center justify-center rounded-full bg-pink-100"
                >
                  -
                </button>

                <span className="text-lg">{qty}</span>

                <button
                  onClick={() => setQty(qty + 1)}
                  className="w-8 h-8 flex items-center justify-center rounded-full bg-pink-100"
                >
                  +
                </button>
              </div>
            </div>

            {/* Nút */}
            <div className="mt-6 flex gap-4">
              <button
                onClick={addToCart}
                className="px-6 py-3 rounded-full bg-pink-500 text-white shadow hover:bg-pink-600"
              >
                Thêm vào giỏ
              </button>

              <button
                onClick={buyNow}
                className="px-6 py-3 rounded-full border border-pink-500 text-pink-600 hover:bg-pink-50"
              >
                Mua ngay
              </button>
            </div>
          </div>
        </div>

        {/* === Tabs === */}
        <div className="mt-12 bg-white rounded-3xl p-8 shadow">

          <div className="flex gap-6 border-b pb-3">
            <button
              onClick={() => setActiveTab("description")}
              className={`pb-2 ${
                activeTab === "description"
                  ? "border-pink-500 border-b-2 text-pink-600"
                  : "text-gray-600"
              }`}
            >
              Mô tả
            </button>

            <button
              onClick={() => setActiveTab("reviews")}
              className={`pb-2 ${
                activeTab === "reviews"
                  ? "border-pink-500 border-b-2 text-pink-600"
                  : "text-gray-600"
              }`}
            >
              Đánh giá ({reviews.length})
            </button>
          </div>

          {/* MÔ TẢ */}
          {activeTab === "description" && (
            <div className="mt-4 text-gray-700 leading-relaxed whitespace-pre-line">
              {product.description}
            </div>
          )}

          {/* REVIEW */}
          {activeTab === "reviews" && (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-10 mt-6">

              {/* List review */}
              <div className="md:col-span-2">
                {reviews.length === 0 && (
                  <p className="text-gray-500">Chưa có đánh giá nào.</p>
                )}

                <div className="space-y-5 max-h-96 overflow-y-auto pr-2">
                  {reviews.map((rv) => (
                    <div
                      key={rv._id}
                      className="p-4 rounded-2xl bg-pink-50 border border-pink-100"
                    >
                      <div className="flex justify-between">
                        <b className="text-[#4b2c35]">{rv.name}</b>
                        <span className="text-gray-500 text-sm">
                          {new Date(rv.createdAt).toLocaleDateString("vi-VN")}
                        </span>
                      </div>

                      <div className="text-yellow-500 text-sm mb-2">
                        {"★".repeat(rv.rating)}{" "}
                        <span className="text-gray-300">
                          {"★".repeat(5 - rv.rating)}
                        </span>
                      </div>

                      <p className="text-gray-700">{rv.comment}</p>
                    </div>
                  ))}
                </div>
              </div>

              {/* Form review */}
              <div className="p-4 bg-pink-50 border rounded-2xl">
                <h3 className="font-semibold text-[#4b2c35] mb-4">
                  Viết đánh giá
                </h3>

                <form onSubmit={submitReview}>
                  <label className="text-sm">Số sao</label>
                  <select
                    className="w-full mt-1 p-2 border rounded-lg"
                    value={rating}
                    onChange={(e) => setRating(Number(e.target.value))}
                  >
                    <option value={5}>5 - Tuyệt vời</option>
                    <option value={4}>4 - Rất tốt</option>
                    <option value={3}>3 - Bình thường</option>
                    <option value={2}>2 - Không hài lòng</option>
                    <option value={1}>1 - Rất tệ</option>
                  </select>

                  <label className="text-sm mt-4 block">Nhận xét</label>
                  <textarea
                    rows={4}
                    className="w-full p-2 border rounded-lg mt-1"
                    value={comment}
                    onChange={(e) => setComment(e.target.value)}
                  />

                  <button
                    type="submit"
                    disabled={loadingReview}
                    className="mt-4 w-full bg-pink-500 text-white py-2 rounded-full hover:bg-pink-600"
                  >
                    {loadingReview ? "Đang gửi..." : "Gửi đánh giá"}
                  </button>
                </form>
              </div>
            </div>
          )}
        </div>

        {/* === SẢN PHẨM LIÊN QUAN === */}
        {related.length > 0 && (
          <div className="mt-14">
            <h2 className="text-xl font-bold mb-4 text-[#4b2c35]">
              Sản phẩm liên quan
            </h2>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-5">
              {related.map((item) => (
                <div
                  key={item._id}
                  onClick={() => navigate(`/product/${item._id}`)}
                  className="bg-white shadow rounded-2xl p-3 hover:-translate-y-1 transition cursor-pointer"
                >
                  <img
                    src={API_BASE + item.images?.[0]}
                    alt=""
                    className="w-full h-40 object-cover rounded-xl"
                  />
                  <p className="mt-2 font-medium text-[#4b2c35]">
                    {item.name}
                  </p>
                  <p className="text-pink-600 font-bold">
                    {(item.discountPrice || item.price).toLocaleString()}₫
                  </p>
                </div>
              ))}
            </div>
          </div>
        )}

      </div>
    </div>
  );
};

export default ProductDetail;
